function ( $email ) {
				$email = trim( $email );

				// Extract email from "Name <email>" format.
				if ( preg_match( '/<(.+?)>/', $email, $matches ) ) {
					$email = $matches[1];
				}

				return filter_var( $email, FILTER_VALIDATE_EMAIL ) ? sanitize_email( $email ) : '';
			}

